CREATE OR REPLACE VIEW vr_lon_spec_list (doc_no, sort_order, redemption_text, include_desc, coll_ref_type, coll_ref_description, coll_type, coll_description, redemption_type, redemption_desc, doc_detail, doc_address) AS select sc_lon_req_coll_law_head.doc_no
, sc_lon_m_contract_coll.collateral_no    as sort_order
, sc_lon_req_coll_law_head.redemption_text as redemption_text

 ,( case sc_lon_req_coll_law_head.include_status when '01' then 'ใช้ค้ำสัญญาเดียว' when '02' then 'ค้ำประกันร่วม(หลัก)' when '03' then 'ค้ำประกันร่วม(ย่อย)' end )  as include_desc

, sc_lon_m_ucf_coll_ref_type.coll_ref_type
, sc_lon_m_ucf_coll_ref_type.coll_ref_description as coll_ref_description /*ประเภทหลักประกัน : 05 / 06 / 08  */
, sc_lon_m_ucf_coll_type.coll_type
, sc_lon_m_ucf_coll_type.coll_description as coll_description /* ค้ำเงินกู้ : 01 spec/ 02 norm  /03 restruc*/
, sc_lon_ucf_redemption.redemption_type 
, sc_lon_ucf_redemption.redemption_desc  as redemption_desc /*สถานะ: 0 / 1  / 2  / 3 / 4  */
, pka_estate.fp_get_doc_detail( sc_lon_req_coll_law_head.doc_no ) as doc_detail
, pka_estate.fp_get_doc_address( sc_lon_req_coll_law_head.doc_no )as doc_address
FROM  sc_lon_req_coll_law_head
,sc_lon_m_contract_coll
,sc_lon_m_ucf_coll_ref_type            
,sc_lon_m_ucf_coll_type
,sc_lon_ucf_redemption
where 1=1
and  sc_lon_req_coll_law_head.coll_ref_type = sc_lon_m_ucf_coll_ref_type.coll_ref_type
and  sc_lon_req_coll_law_head.coll_type =     sc_lon_m_ucf_coll_type.coll_type
and  sc_lon_req_coll_law_head.doc_no = sc_lon_m_contract_coll.ref_own_no 
and sc_lon_req_coll_law_head.redemption_type = sc_lon_ucf_redemption.redemption_type 
